(function () {
  function addStyle(){ if(document.getElementById('bog-style'))return; var s=document.createElement('style'); s.id='bog-style'; s.textContent='.bog-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.bog-controls{display:flex;gap:10px;flex-wrap:wrap;align-items:end}.bog-card{margin-top:12px;padding:12px;border-radius:10px;background:#f8fafc;border:1px solid #e5e7eb}.bog-table{width:100%;border-collapse:collapse}.bog-table td,.bog-table th{border:1px solid #e5e7eb;padding:6px;text-align:right}.bog-table th{text-align:center}.bog-out{padding:10px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff;margin-top:10px}'; document.head.appendChild(s); }
  function mount(host){ if(!host||host.dataset.bogMounted)return; host.dataset.bogMounted='1'; addStyle(); var names=['log n','n','n log n','n²','2^n','n!']; host.innerHTML='<div class="bog-wrap"><h4>🚀 So sánh tăng trưởng Big-O</h4><div class="bog-controls"><label>f(n)<select data-f>'+names.map(function(n){return '<option>'+n+'</option>';}).join('')+'</select></label><label>g(n)<select data-g>'+names.map(function(n){return '<option>'+n+'</option>';}).join('')+'</select></label><label>n<input data-n type="number" min="1" max="100" value="10"></label></div><div class="bog-card"><table class="bog-table"></table><div class="bog-out"></div></div></div>'; host.querySelector('[data-g]').value='n²'; function val(name,n){if(name==='log n')return Math.log2(Math.max(2,n)); if(name==='n')return n; if(name==='n log n')return n*Math.log2(Math.max(2,n)); if(name==='n²')return n*n; if(name==='2^n')return Math.pow(2,Math.min(n,50)); var r=1; for(var i=2;i<=Math.min(n,30);i++)r*=i; return r;} function rank(name){return {'log n':1,'n':2,'n log n':3,'n²':4,'2^n':5,'n!':6}[name];} function fmt(x){return x>1e6?x.toExponential(2):x.toFixed(2);} function paint(){var f=host.querySelector('[data-f]').value,g=host.querySelector('[data-g]').value,n=Math.max(1,Math.min(100,+host.querySelector('[data-n]').value||1)), pts=[1,Math.max(2,Math.floor(n/4)),Math.max(3,Math.floor(n/2)),n], rows=pts.map(function(k){var a=val(f,k),b=val(g,k);return '<tr><td>'+k+'</td><td>'+fmt(a)+'</td><td>'+fmt(b)+'</td><td>'+fmt(a/b)+'</td></tr>';}).join(''); host.querySelector('.bog-table').innerHTML='<tr><th>n</th><th>f='+f+'</th><th>g='+g+'</th><th>f/g</th></tr>'+rows; var rf=rank(f),rg=rank(g), msg=rf===rg?'f(n)=Θ(g(n)): cùng bậc tăng trưởng.':rf<rg?'f(n)=O(g(n)): f tăng chậm hơn hoặc bằng g.':'g(n)=O(f(n)): g tăng chậm hơn hoặc bằng f.'; host.querySelector('.bog-out').textContent=msg;} host.querySelectorAll('input,select').forEach(function(e){e.addEventListener('input',paint);e.addEventListener('change',paint);}); paint(); }
  document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('[data-demo="big-o-growth-comparator"]').forEach(mount);});
}());
